## 4. TUI Command Registration Pattern

**Files**:
- `/home/openclaw/code/tuicraft/src/ui/commands.ts` - Command parser
- `/home/openclaw/code/tuicraft/src/ui/tui.ts` - TUI executor
- `/home/openclaw/code/tuicraft/src/daemon/commands.ts` - Daemon dispatcher

Commands are defined as union types:

```typescript
// ui/commands.ts
export type Command =
  | { type: "invite"; target: string }
  | { type: "kick"; target: string }
  | { type: "leave" }
  | { type: "unimplemented"; feature: string };

export function parseCommand(input: string): Command {
  switch (cmd) {
    case "/invite":
      return rest ? { type: "invite", target: rest } : { type: "say", message: input };
    case "/ginvite":
    case "/gkick":
    case "/gleave":
    case "/gpromote":
      return { type: "unimplemented", feature: "Guild management" };
  }
}
```

The command is then dispatched in `tui.ts`:

```typescript
case "invite":
  state.handle.invite(cmd.target);
  break;
case "kick":
  state.handle.uninvite(cmd.target);
  break;
```

Guild commands (`/ginvite`, `/gkick`, `/gleave`, `/gpromote`) are currently marked as unimplemented (lines 125-129 in `ui/commands.ts`).

