## 5. IPC Dispatch Pattern (Daemon ↔ TUI)

**File**: `/home/openclaw/code/tuicraft/src/daemon/commands.ts`

The daemon exposes commands via an `IpcCommand` union type:

```typescript
export type IpcCommand =
  | { type: "chat"; message: string }
  | { type: "whisper"; target: string; message: string }
  | { type: "invite"; target: string }
  | { type: "kick"; target: string }
  | { type: "friends" }
  | { type: "friends_json" }
  | { type: "add_friend"; target: string }
  | { type: "del_friend"; target: string }
  | { type: "ignored" }
  | { type: "ignored_json" }
  | { type: "unimplemented"; feature: string };

export async function dispatchCommand(
  cmd: IpcCommand,
  handle: WorldHandle,
  events: RingBuffer<EventEntry>,
  socket: IpcSocket,
  cleanup: () => void,
): Promise<boolean> {
  switch (cmd.type) {
    case "friends": {
      const friends = handle.getFriends();
      writeLines(socket, formatFriendList(friends).split("\n"));
      return false;
    }
    case "add_friend":
      handle.addFriend(cmd.target);
      writeLines(socket, ["OK"]);
      return false;
    // ... etc
  }
}
```

