## 7. Event System and Session Log

**Files**:
- `/home/openclaw/code/tuicraft/src/lib/session-log.ts`
- `/home/openclaw/code/tuicraft/src/daemon/commands.ts` (lines 576-634)

Events are stored in a ring buffer and logged:

```typescript
// session-log.ts
export type LogEntry = {
  type: string;
  sender: string;
  message: string;
  channel?: string;
};

// daemon/commands.ts
export function onGroupEvent(
  event: GroupEvent,
  events: RingBuffer<EventEntry>,
  log: SessionLog,
): void {
  const text = formatGroupEvent(event);
  const obj = formatGroupEventObj(event);
  events.push({ text, json: JSON.stringify(obj) });
  log.append(obj as LogEntry).catch(() => {});
}

export function onFriendEvent(
  event: FriendEvent,
  events: RingBuffer<EventEntry>,
  log: SessionLog,
): void {
  const text = formatFriendEvent(event);
  const obj = formatFriendEventObj(event);
  if (obj) {
    events.push({ text, json: JSON.stringify(obj) });
    log.append(obj as LogEntry).catch(() => {});
  }
}
```

Events are registered in the dispatcher:

```typescript
// client.ts lines 346-348
conn.entityStore.onEvent((event) => conn.onEntityEvent?.(event));
conn.friendStore.onEvent((event) => conn.onFriendEvent?.(event));
conn.ignoreStore.onEvent((event) => conn.onIgnoreEvent?.(event));
```

---

## 8. Formatting Pattern for Display

**File**: `/home/openclaw/code/tuicraft/src/ui/format.ts`

Two formats for each feature: human-readable text and JSON:

```typescript
// Lines 276-289
export function formatFriendList(friends: FriendEntry[]): string {
  if (friends.length === 0) return "[friends] No friends on your list";
  const lines = friends.map((f) => {
    const name = f.name || `guid:${Number(f.guid & 0xffffffffn)}`;
    if (f.status === FriendStatus.OFFLINE) return `  ${name} — Offline`;
    const cls = CLASS_NAMES[f.playerClass] ?? `class ${f.playerClass}`;
    const statusLabel = friendStatusLabel(f.status);
    return `  ${name} — ${statusLabel}, Level ${f.level} ${cls}`;
  });
  const online = friends.filter((f) => f.status !== FriendStatus.OFFLINE).length;
  return `[friends] ${online}/${friends.length} online\n${lines.join("\n")}`;
}

export function formatFriendListJson(friends: FriendEntry[]): string {
  return JSON.stringify({
    type: "FRIENDS",
    count: friends.length,
    online: friends.filter((f) => f.status !== FriendStatus.OFFLINE).length,
    friends: friends.map((f) => ({
      guid: `0x${f.guid.toString(16)}`,
      name: f.name,
      note: f.note,
      status: friendStatusLabel(f.status).toUpperCase(),
      level: f.level,
      class: CLASS_NAMES[f.playerClass] ?? `class ${f.playerClass}`,
    })),
  });
}
```

