    writeLines(socket, ["OK"]);
    return false;
  ```

- Returns `Promise<boolean>`: `false` = keep connection, `true` = exit

---

### 4. **WorldHandle Interface** (`src/wow/client.ts`)

**Friend/Ignore Methods:**
```typescript
export type WorldHandle = {
  getFriends(): FriendEntry[];
  addFriend(name: string): void;
  removeFriend(name: string): void;
  onFriendEvent(cb: (event: FriendEvent) => void): void;

  getIgnored(): IgnoreEntry[];
  addIgnore(name: string): void;
  removeIgnore(name: string): void;
  onIgnoreEvent(cb: (event: IgnoreEvent) => void): void;
}
```

**Implementation in `worldSession()`:**
```typescript
const handle: WorldHandle = {
  getFriends() {
    return conn.friendStore.all();
  },
  addFriend(name) {
    sendPacket(
      conn,
      GameOpcode.CMSG_ADD_FRIEND,
      buildAddFriend(name, ""),
    );
  },
  removeFriend(name) {
    const friend = conn.friendStore.findByName(name);
    if (!friend) {
      conn.onMessage?.({
        type: ChatType.SYSTEM,
        sender: "",
        message: `"${name}" is not on your friends list.`,
      });
      return;
    }
    sendPacket(
      conn,
      GameOpcode.CMSG_DEL_FRIEND,
      buildDelFriend(friend.guid),
    );
  },
  onFriendEvent(cb) {
    conn.onFriendEvent = cb;
  },
};
```

**Key pattern:** Methods immediately send opcodes; server response updates store, which fires events.

---

### 5. **Packet Handler Wiring** (`src/wow/client.ts`)

**In `worldSession()`, handlers are registered via opcode dispatch:**
```typescript
conn.dispatch.on(GameOpcode.SMSG_CONTACT_LIST, (r) =>
  handleContactList(conn, r),
);
conn.dispatch.on(GameOpcode.SMSG_FRIEND_STATUS, (r) =>
  handleFriendStatus(conn, r),
);
```

**Handler Implementation** (`src/wow/world-handlers.ts`):

`handleContactList()` — parses initial friend/ignore list:
```typescript
export function handleContactList(conn: WorldConn, r: PacketReader): void {
  const list = parseContactList(r);
  const friends: FriendEntry[] = [];
  for (const contact of list.contacts) {
    if (!(contact.flags & SocialFlag.FRIEND)) continue;
    const guidLow = Number(contact.guid & 0xffffffffn);
    const name = conn.nameCache.get(guidLow) ?? "";
    friends.push({
      guid: contact.guid,
      name,
      note: contact.note,
      status: contact.status ?? 0,
      area: contact.area ?? 0,
      level: contact.level ?? 0,
      playerClass: contact.playerClass ?? 0,
    });
    if (!name) ensureNameQuery(conn, contact.guid);
  }
  conn.friendStore.set(friends);
  // ... same for ignored
}
```

`handleFriendStatus()` — handles updates:
```typescript
export function handleFriendStatus(conn: WorldConn, r: PacketReader): void {
  const packet = parseFriendStatus(r);
  const guidLow = Number(packet.guid & 0xffffffffn);

  switch (packet.result) {
    case FriendResult.ADDED_ONLINE:
    case FriendResult.ADDED_OFFLINE: {
      const name = conn.nameCache.get(guidLow) ?? "";
      conn.friendStore.add({
        guid: packet.guid,
        name,
        note: packet.note ?? "",
        status: packet.status ?? 0,
        area: packet.area ?? 0,
        level: packet.level ?? 0,
        playerClass: packet.playerClass ?? 0,
      });
      if (!name) ensureNameQuery(conn, packet.guid);
      break;
    }
    case FriendResult.ONLINE:
      conn.friendStore.update(packet.guid, {
        status: packet.status ?? FriendStatus.ONLINE,
        area: packet.area ?? 0,
        level: packet.level ?? 0,
        playerClass: packet.playerClass ?? 0,
      });
      break;
    case FriendResult.OFFLINE:
      conn.friendStore.update(packet.guid, { status: FriendStatus.OFFLINE });
      break;
    case FriendResult.REMOVED:
      conn.friendStore.remove(packet.guid);
      break;
    // ... error cases fire onFriendEvent with error type
  }
}
```

---

### 6. **Formatting** (`src/ui/format.ts`)

**Text Format:**
```typescript
export function formatFriendList(friends: FriendEntry[]): string {
  if (friends.length === 0) return "[friends] No friends on your list";
  const lines = friends.map((f) => {
    const name = f.name || `guid:${Number(f.guid & 0xffffffffn)}`;
    if (f.status === FriendStatus.OFFLINE) return `  ${name} — Offline`;
    const cls = CLASS_NAMES[f.playerClass] ?? `class ${f.playerClass}`;
    const statusLabel = friendStatusLabel(f.status);
    return `  ${name} — ${statusLabel}, Level ${f.level} ${cls}`;
  });
  const online = friends.filter(
    (f) => f.status !== FriendStatus.OFFLINE,
  ).length;
  return `[friends] ${online}/${friends.length} online\n${lines.join("\n")}`;
}
```

**Output:**
```
[friends] 2/4 online
  Azeroth — Online, Level 70 Mage
  Blackthorn — Online, Level 70 Warrior
  Crimson — Offline
  Draco — AFK
```

**JSON Format:**
```typescript
export function formatFriendListJson(friends: FriendEntry[]): string {
  return JSON.stringify({
    type: "FRIENDS",
    count: friends.length,
    online: friends.filter((f) => f.status !== FriendStatus.OFFLINE).length,
    friends: friends.map((f) => ({
      guid: `0x${f.guid.toString(16)}`,
      name: f.name,
      note: f.note,
      status: friendStatusLabel(f.status).toUpperCase(),
      level: f.level,
      class: CLASS_NAMES[f.playerClass] ?? `class ${f.playerClass}`,
      area: f.area,
    })),
  });
}
```

**Event Formatting:**
```typescript
export function formatFriendEvent(event: FriendEvent): string | undefined {
  switch (event.type) {
    case "friend-online": {
      const f = event.friend;
      const cls = CLASS_NAMES[f.playerClass] ?? "";
      const lvl = f.level ? `Level ${f.level}` : "";
      const detail = [lvl, cls].filter(Boolean).join(" ");
      return `[friends] ${f.name || "Unknown"} is now online${detail ? ` (${detail})` : ""}`;
    }
    case "friend-offline":
      return `[friends] ${event.name || "Unknown"} went offline`;
    case "friend-added":
      return `[friends] ${f.name || "Unknown"} added to friends list`;
    case "friend-removed":
      return `[friends] ${event.name || "Unknown"} removed from friends list`;
    case "friend-error":
      return `[friends] Error: ${friendResultLabel(event.result)}`;
    // ...
  }
}
```

---

### 7. **IPC Socket Protocol**

**Request/Response Pattern:**
- Client sends: `FRIENDS\n` or `ADD_FRIEND Voidtrix\n`
- Daemon responds with formatted output or error
- Blank line terminates response: `\n`

**Socket write function:**
```typescript
export function writeLines(socket: IpcSocket, lines: string[]): void {
  for (const line of lines) socket.write(line + "\n");
  socket.write("\n");
}
```

**Result examples:**
```
FRIENDS
[friends] 2/4 online
  Azeroth — Online, Level 70 Mage
  Blackthorn — Online, Level 70 Warrior

ADD_FRIEND Xiara
OK

```

---

### 8. **Event Routing in Daemon** (`src/daemon/server.ts`)

**Hook setup:**
```typescript
export function startDaemonServer(args: DaemonServerArgs): DaemonServer {
  const { handle, sock, log, onActivity, onStop } = args;
  const events = new RingBuffer<EventEntry>(1000);
  handle.onMessage((msg) => onChatMessage(msg, events, log));
  handle.onGroupEvent((event) => onGroupEvent(event, events, log));
  handle.onEntityEvent((event) => onEntityEvent(event, events, log));
  handle.onFriendEvent((event) => onFriendEvent(event, events, log));
  handle.onIgnoreEvent((event) => onIgnoreEvent(event, events, log));
  // ...
}
```

**Event handler stores text and JSON:**
```typescript
export function onFriendEvent(
  event: FriendEvent,
  events: RingBuffer<EventEntry>,
  log: SessionLog,
): void {
  const text = formatFriendEvent(event);
  const obj = formatFriendEventObj(event);
  if (obj) {
    events.push({ text, json: JSON.stringify(obj) });
    log.append(obj as LogEntry).catch(() => {});
  }
}
```

**Ring buffer holds up to 1000 events.** Clients can `READ` or `READ_WAIT` to get buffered events.

---

### 9. **Mock Handle Pattern** (`src/test/mock-handle.ts`)

For testing, a mock WorldHandle is created:
```typescript
export function createMockHandle(): {
  handle: WorldHandle;
  sendFriendStatus(packet: any): void;
  // ... other methods
} {
  // Implementation returns handle with method mocks
}
```

**Key insight:** Two mocks exist:
1. Shared: `src/test/mock-handle.ts` (used in tests)
2. Inline: `src/daemon/start.test.ts` (used for live integration)

**Must update both when adding WorldHandle methods.**

---

### 10. **Protocol Layer** (`src/wow/protocol/social.ts`)

**Constants:**
```typescript
export const SocialFlag = {
  FRIEND: 0x01,
  IGNORED: 0x02,
  MUTED: 0x04,
};

export const FriendStatus = {
  OFFLINE: 0,
  ONLINE: 1,
  AFK: 2,
  DND: 4,
};

export const FriendResult = {
  DB_ERROR: 0x00,
  LIST_FULL: 0x01,
  // ... 15+ result codes
};
```

**Packet builders:**
```typescript
export function buildAddFriend(name: string, note: string): Uint8Array {
  const w = new PacketWriter();
  w.cString(name);
  w.cString(note);
  return w.finish();
}

export function buildDelFriend(guid: bigint): Uint8Array {
  const w = new PacketWriter();
  w.uint64LE(guid);
  return w.finish();
}
```

**Packet parsers:**
```typescript
export function parseContactList(r: PacketReader): ContactList {
  const listMask = r.uint32LE();
  const count = r.uint32LE();
  const contacts: ContactEntry[] = [];
  for (let i = 0; i < count; i++) {
    const guid = r.uint64LE();
    const flags = r.uint32LE();
    const note = r.cString();
    const entry: ContactEntry = { guid, flags, note };
    if (flags & SocialFlag.FRIEND) {
      entry.status = r.uint8();
      if (entry.status !== 0) {
        entry.area = r.uint32LE();
        entry.level = r.uint32LE();
        entry.playerClass = r.uint32LE();
      }
    }
    contacts.push(entry);
  }
  return { listMask, contacts };
}
```

