225→function drainWorldPackets(conn: WorldConn): void {
226→  while (true) {
227→    if (!conn.pendingHeader) {
228→      if (conn.buf.length < INCOMING_HEADER_SIZE) break;
229→      conn.pendingHeader = decryptIncomingHeader(
230→        conn.buf.drain(INCOMING_HEADER_SIZE),
231→        conn.arc4,
232→      );
233→    }
234→    const bodySize = conn.pendingHeader.size - 2;
235→    if (conn.buf.length < bodySize) break;
236→
237→    const { opcode } = conn.pendingHeader;
238→    conn.pendingHeader = undefined;
239→    try {
240→      conn.dispatch.handle(opcode, new PacketReader(conn.buf.drain(bodySize)));
241→    } catch (err) {
242→      if (err instanceof Error) {
243→        conn.onPacketError?.(opcode, err);
244→      }
245→    }
246→  }
247→}
