249→async function authenticateWorld(
250→  conn: WorldConn,
251→  config: ClientConfig,
252→  auth: AuthResult,
253→): Promise<void> {
254→  const challenge = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_CHALLENGE);
255→  challenge.uint32LE();
256→  const serverSeed = challenge.bytes(4);
257→
258→  const body = await buildWorldAuthPacket(
259→    config.account,
260→    auth.sessionKey,
261→    serverSeed,
262→    auth.realmId,
263→    config.clientSeed,
264→  );
265→  conn.socket.write(buildOutgoingPacket(GameOpcode.CMSG_AUTH_SESSION, body));
266→  conn.arc4 = new Arc4(auth.sessionKey);
267→
268→  const resp = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_RESPONSE);
269→  const status = resp.uint8();
270→  if (status !== 0x0c) {
271→    const names: Record<number, string> = {
272→      0x0d: "system error",
273→      0x15: "account in use",
274→    };
275→    const label = names[status] ?? `status 0x${status.toString(16)}`;
276→    throw new Error(`World auth failed: ${label}`);
277→  }
278→}
