280→async function selectCharacter(
281→  conn: WorldConn,
282→  config: ClientConfig,
283→): Promise<void> {
284→  sendPacket(conn, GameOpcode.CMSG_CHAR_ENUM);
285→
286→  const enumReader = await conn.dispatch.expect(GameOpcode.SMSG_CHAR_ENUM);
287→  const chars = parseCharacterList(enumReader);
288→  const char = chars.find(
289→    (c) => c.name.toLowerCase() === config.character.toLowerCase(),
290→  );
291→  if (!char) {
292→    throw new Error(
293→      `Character "${config.character}" not found. Available: ${chars.map((c) => c.name).join(", ")}`,
294→    );
295→  }
296→
297→  conn.selfName = char.name;
298→  conn.selfGuidLow = char.guidLow;
299→  conn.selfGuidHigh = char.guidHigh;
300→
301→  const w = new PacketWriter();
302→  w.uint32LE(char.guidLow);
303→  w.uint32LE(char.guidHigh);
304→  sendPacket(conn, GameOpcode.CMSG_PLAYER_LOGIN, w.finish());
305→
306→  await conn.dispatch.expect(GameOpcode.SMSG_LOGIN_VERIFY_WORLD);
307→}
