309→function startPingLoop(
310→  conn: WorldConn,
311→  intervalMs: number,
312→): ReturnType<typeof setInterval> {
313→  return setInterval(() => {
314→    const w = new PacketWriter();
315→    w.uint32LE(0);
316→    w.uint32LE(0);
317→    sendPacket(conn, GameOpcode.CMSG_PING, w.finish());
318→  }, intervalMs);
319→}
