 48→  const guidLow = Number(guid & 0xffffffffn);
 49→  if (conn.pendingNameQueries.has(`player:${guidLow}`)) return;
 50→  conn.pendingNameQueries.add(`player:${guidLow}`);
 51→  sendPacket(
 52→    conn,
 53→    GameOpcode.CMSG_NAME_QUERY,
 54→    buildNameQuery(guidLow, Number((guid >> 32n) & 0xffffffffn)),
 55→  );
 56→}
