 88→export function resolveAndDeliver(conn: WorldConn, raw: RawChatMessage): void {
 89→  if (raw.senderGuidLow === 0) {
 90→    deliverMessage(conn, raw, "");
 91→    return;
 92→  }
 93→
 94→  if (conn.ignoreStore.has(raw.senderGuidLow)) return;
 95→
 96→  const cached = conn.nameCache.get(raw.senderGuidLow);
 97→  if (cached !== undefined) {
 98→    deliverMessage(conn, raw, cached);
 99→    return;
100→  }
101→
102→  const pending = conn.pendingMessages.get(raw.senderGuidLow);
103→  if (pending) {
104→    pending.push(raw);
105→  } else {
106→    conn.pendingMessages.set(raw.senderGuidLow, [raw]);
107→    sendPacket(
108→      conn,
109→      GameOpcode.CMSG_NAME_QUERY,
110→      buildNameQuery(raw.senderGuidLow, raw.senderGuidHigh),
111→    );
112→  }
113→}
