135→export function handleNameQueryResponse(
136→  conn: WorldConn,
137→  r: PacketReader,
138→): void {
139→  const result = parseNameQueryResponse(r);
140→
141→  const name = result.found && result.name ? result.name : "";
142→  conn.pendingNameQueries.delete(`player:${result.guidLow}`);
143→  if (result.found && result.name) {
144→    conn.nameCache.set(result.guidLow, result.name);
145→    for (const entity of conn.entityStore.all()) {
146→      if (
147→        entity.objectType === ObjectType.PLAYER &&
148→        Number(entity.guid & 0xffffffffn) === result.guidLow &&
149→        !entity.name
150→      ) {
151→        conn.entityStore.setName(entity.guid, result.name);
152→      }
153→    }
154→    for (const friend of conn.friendStore.all()) {
155→      if (
156→        Number(friend.guid & 0xffffffffn) === result.guidLow &&
157→        !friend.name
158→      ) {
159→        conn.friendStore.setName(friend.guid, result.name);
160→      }
161→    }
162→    for (const entry of conn.ignoreStore.all()) {
163→      if (Number(entry.guid & 0xffffffffn) === result.guidLow && !entry.name) {
164→        conn.ignoreStore.setName(entry.guid, result.name);
165→      }
166→    }
167→  }
168→
169→  const pending = conn.pendingMessages.get(result.guidLow);
170→  if (!pending) return;
171→  for (const raw of pending) deliverMessage(conn, raw, name);
172→  conn.pendingMessages.delete(result.guidLow);
173→}
