179→    conn.onMessage?.({
180→      type: ChatType.SYSTEM,
181→      sender: "",
182→      message: `Joined channel: ${event.channel}`,
183→    });
184→  } else if (event.type === "left") {
185→    const idx = conn.channels.indexOf(event.channel);
186→    if (idx !== -1) conn.channels.splice(idx, 1);
187→    conn.onMessage?.({
188→      type: ChatType.SYSTEM,
189→      sender: "",
190→      message: `Left channel: ${event.channel}`,
191→    });
192→  } else if (event.type === "error") {
193→    conn.onMessage?.({
194→      type: ChatType.SYSTEM,
195→      sender: "",
196→      message: event.message,
197→    });
198→  }
199→}
