342→export function handleUpdateObject(conn: WorldConn, r: PacketReader): void {
343→  const entries = parseUpdateObject(r);
344→  for (const entry of entries) {
345→    switch (entry.type) {
346→      case "create": {
347→        const { _changed: _co, ...objFields } = extractObjectFields(
348→          entry.fields,
349→        );
350→        let extraFields: Record<string, unknown> = {};
351→        if (
352→          entry.objectType === ObjectType.UNIT ||
353→          entry.objectType === ObjectType.PLAYER
354→        ) {
355→          const { _changed: _cu, ...rest } = extractUnitFields(entry.fields);
356→          extraFields = rest;
357→        } else if (entry.objectType === ObjectType.GAMEOBJECT) {
358→          const { _changed: _cg, ...rest } = extractGameObjectFields(
359→            entry.fields,
360→          );
361→          extraFields = rest;
362→        }
363→        const cachedName = lookupCachedName(
364→          conn,
365→          entry.guid,
366→          entry.objectType,
367→          objFields.entry,
368→        );
369→        conn.entityStore.create(entry.guid, entry.objectType, {
370→          ...objFields,
371→          ...extraFields,
372→          ...(cachedName ? { name: cachedName } : {}),
373→          ...(entry.position ? { position: entry.position } : {}),
374→          rawFields: new Map(entry.fields),
375→        } as any);
376→        if (!cachedName) {
377→          queryEntityName(conn, entry.guid, entry.objectType, objFields.entry);
378→        }
379→        break;
380→      }
381→      case "values": {
382→        const entity = conn.entityStore.get(entry.guid);
383→        if (!entity) break;
384→        const objFields = extractObjectFields(entry.fields, entity.rawFields);
385→        let extraFields: Record<string, unknown> = {};
386→        if (
387→          entity.objectType === ObjectType.UNIT ||
388→          entity.objectType === ObjectType.PLAYER
389→        ) {
390→          extraFields = extractUnitFields(entry.fields, entity.rawFields);
391→        } else if (entity.objectType === ObjectType.GAMEOBJECT) {
392→          extraFields = extractGameObjectFields(entry.fields);
393→        }
394→        const allChanged = [
395→          ...(objFields._changed || []),
396→          ...((extraFields as any)._changed || []),
397→        ];
398→        const merged: Record<string, unknown> = {};
399→        for (const key of allChanged) {
400→          if (key in extraFields) merged[key] = (extraFields as any)[key];
401→          else if (key in objFields) merged[key] = (objFields as any)[key];
402→        }
403→        conn.entityStore.update(entry.guid, merged);
404→        for (const [k, v] of entry.fields) {
405→          const existing = conn.entityStore.get(entry.guid);
406→          if (existing) existing.rawFields.set(k, v);
407→        }
408→        break;
409→      }
410→      case "movement": {
411→        conn.entityStore.setPosition(entry.guid, entry.position);
412→        break;
413→      }
414→      case "outOfRange": {
415→        for (const guid of entry.guids) conn.entityStore.destroy(guid);
416→        break;
417→      }
418→      case "nearObjects": {
419→        break;
420→      }
421→    }
422→  }
423→}
