425→export function handleCompressedUpdateObject(
426→  conn: WorldConn,
427→  r: PacketReader,
428→): void {
429→  const uncompressedSize = r.uint32LE();
430→  const compressed = r.bytes(r.remaining);
431→  const decompressed = inflateSync(compressed);
432→  if (decompressed.length !== uncompressedSize) {
433→    throw new Error(
434→      `Compressed update size mismatch: expected ${uncompressedSize}, got ${decompressed.length}`,
435→    );
436→  }
437→  handleUpdateObject(conn, new PacketReader(new Uint8Array(decompressed)));
438→}
