446→export function lookupCachedName(
447→  conn: WorldConn,
448→  guid: bigint,
449→  objectType: number,
450→  entry: number | undefined,
451→): string | undefined {
452→  if (objectType === ObjectType.PLAYER) {
453→    const guidLow = Number(guid & 0xffffffffn);
454→    return conn.nameCache.get(guidLow);
455→  }
456→  if (entry === undefined) return undefined;
457→  if (objectType === ObjectType.UNIT) return conn.creatureNameCache.get(entry);
458→  if (objectType === ObjectType.GAMEOBJECT)
459→    return conn.gameObjectNameCache.get(entry);
460→  return undefined;
461→}
462→
463→export function queryEntityName(
464→  conn: WorldConn,
465→  guid: bigint,
466→  objectType: number,
467→  entry: number | undefined,
468→): void {
469→  if (objectType === ObjectType.PLAYER) {
470→    const guidLow = Number(guid & 0xffffffffn);
471→    const key = `player:${guidLow}`;
472→    if (conn.pendingNameQueries.has(key)) return;
473→    conn.pendingNameQueries.add(key);
474→    const w = new PacketWriter();
475→    w.uint64LE(guid);
476→    sendPacket(conn, GameOpcode.CMSG_NAME_QUERY, w.finish());
477→    return;
478→  }
479→  if (entry === undefined) return;
480→  const key = `${objectType}:${entry}`;
481→  if (conn.pendingNameQueries.has(key)) return;
482→  conn.pendingNameQueries.add(key);
483→  if (objectType === ObjectType.UNIT) {
484→    sendPacket(
485→      conn,
486→      GameOpcode.CMSG_CREATURE_QUERY,
487→      buildCreatureQuery(entry, guid),
488→    );
489→    return;
490→  }
491→  if (objectType === ObjectType.GAMEOBJECT) {
492→    sendPacket(
493→      conn,
494→      GameOpcode.CMSG_GAMEOBJECT_QUERY,
495→      buildGameObjectQuery(entry, guid),
496→    );
497→    return;
498→  }
499→}
