501→export function handleCreatureQueryResponse(
502→  conn: WorldConn,
503→  r: PacketReader,
504→): void {
505→  const result = parseCreatureQueryResponse(r);
506→  conn.pendingNameQueries.delete(`${ObjectType.UNIT}:${result.entry}`);
507→  if (!result.name) return;
508→  conn.creatureNameCache.set(result.entry, result.name);
509→  for (const entity of conn.entityStore.all()) {
510→    if (entity.entry === result.entry && !entity.name) {
511→      conn.entityStore.setName(entity.guid, result.name);
512→    }
513→  }
514→}
515→
516→export function handleGameObjectQueryResponse(
517→  conn: WorldConn,
518→  r: PacketReader,
519→): void {
520→  const result = parseGameObjectQueryResponse(r);
521→  conn.pendingNameQueries.delete(`${ObjectType.GAMEOBJECT}:${result.entry}`);
522→  if (!result.name) return;
523→  conn.gameObjectNameCache.set(result.entry, result.name);
524→  for (const entity of conn.entityStore.all()) {
525→    if (entity.entry === result.entry) {
526→      if (!entity.name) conn.entityStore.setName(entity.guid, result.name);
527→      if (result.gameObjectType !== undefined) {
528→        conn.entityStore.update(entity.guid, {
529→          gameObjectType: result.gameObjectType,
530→        });
531→      }
532→    }
533→  }
534→}
