536→export function handlePartyMemberStatsMsg(
537→  conn: WorldConn,
538→  r: PacketReader,
539→  isFull = false,
540→): void {
541→  const stats = parsePartyMemberStats(r, isFull);
542→  conn.onGroupEvent?.({
543→    type: "member_stats",
544→    guidLow: stats.guidLow,
545→    online: stats.online,
