552→export function handleContactList(conn: WorldConn, r: PacketReader): void {
553→  const list = parseContactList(r);
554→  const friends: FriendEntry[] = [];
555→  for (const contact of list.contacts) {
556→    if (!(contact.flags & SocialFlag.FRIEND)) continue;
557→    const guidLow = Number(contact.guid & 0xffffffffn);
558→    const name = conn.nameCache.get(guidLow) ?? "";
559→    friends.push({
560→      guid: contact.guid,
561→      name,
562→      note: contact.note,
563→      status: contact.status ?? 0,
564→      area: contact.area ?? 0,
565→      level: contact.level ?? 0,
566→      playerClass: contact.playerClass ?? 0,
567→    });
568→    if (!name) ensureNameQuery(conn, contact.guid);
569→  }
570→  conn.friendStore.set(friends);
571→
572→  const ignored: IgnoreEntry[] = [];
573→  for (const contact of list.contacts) {
574→    if (!(contact.flags & SocialFlag.IGNORED)) continue;
575→    const guidLow = Number(contact.guid & 0xffffffffn);
576→    const name = conn.nameCache.get(guidLow) ?? "";
577→    ignored.push({ guid: contact.guid, name });
578→    if (!name) ensureNameQuery(conn, contact.guid);
579→  }
580→  conn.ignoreStore.set(ignored);
581→}
582→
583→export function handleFriendStatus(conn: WorldConn, r: PacketReader): void {
584→  const packet = parseFriendStatus(r);
585→  const guidLow = Number(packet.guid & 0xffffffffn);
586→
587→  switch (packet.result) {
588→    case FriendResult.ADDED_ONLINE:
589→    case FriendResult.ADDED_OFFLINE: {
590→      const name = conn.nameCache.get(guidLow) ?? "";
591→      conn.friendStore.add({
592→        guid: packet.guid,
593→        name,
594→        note: packet.note ?? "",
595→        status: packet.status ?? 0,
596→        area: packet.area ?? 0,
597→        level: packet.level ?? 0,
598→        playerClass: packet.playerClass ?? 0,
599→      });
600→      if (!name) ensureNameQuery(conn, packet.guid);
601→      break;
602→    }
603→    case FriendResult.ONLINE:
604→      conn.friendStore.update(packet.guid, {
605→        status: packet.status ?? FriendStatus.ONLINE,
606→        area: packet.area ?? 0,
607→        level: packet.level ?? 0,
608→        playerClass: packet.playerClass ?? 0,
609→      });
610→      break;
611→    case FriendResult.OFFLINE:
612→      conn.friendStore.update(packet.guid, { status: FriendStatus.OFFLINE });
613→      break;
614→    case FriendResult.REMOVED:
615→      conn.friendStore.remove(packet.guid);
616→      break;
617→    case FriendResult.IGNORE_ADDED: {
618→      const name = conn.nameCache.get(guidLow) ?? "";
619→      conn.ignoreStore.add({ guid: packet.guid, name });
620→      if (!name) ensureNameQuery(conn, packet.guid);
621→      break;
622→    }
623→    case FriendResult.IGNORE_REMOVED:
624→      conn.ignoreStore.remove(packet.guid);
625→      break;
626→    case FriendResult.IGNORE_FULL:
627→    case FriendResult.IGNORE_SELF:
628→    case FriendResult.IGNORE_NOT_FOUND:
629→    case FriendResult.IGNORE_ALREADY:
630→    case FriendResult.IGNORE_AMBIGUOUS: {
631→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
632→      conn.onIgnoreEvent?.({
633→        type: "ignore-error",
634→        result: packet.result,
635→        name,
636→      });
637→      break;
638→    }
639→    default: {
640→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
641→      conn.onFriendEvent?.({
642→        type: "friend-error",
643→        result: packet.result,
644→        name,
645→      });
646→      break;
647→    }
648→  }
649→}
