 78→export function parseIpcCommand(line: string): IpcCommand | undefined {
 79→  if (line.startsWith("/")) {
 80→    const parsed = parseCommand(line);
 81→    switch (parsed.type) {
 82→      case "say":
 83→      case "yell":
 84→      case "guild":
 85→      case "party":
 86→      case "emote":
 87→      case "dnd":
 88→      case "afk":
 89→        return parsed;
 90→      case "whisper":
 91→        return parsed;
 92→      case "who":
 93→        return parsed.target
 94→          ? { type: "who", filter: parsed.target }
 95→          : { type: "who" };
 96→      case "invite":
 97→      case "kick":
 98→      case "leave":
 99→      case "leader":
100→      case "accept":
101→      case "decline":
102→        return parsed;
103→      case "join-channel":
104→        return {
105→          type: "join_channel",
106→          channel: parsed.channel,
107→          password: parsed.password,
108→        };
109→      case "leave-channel":
110→        return { type: "leave_channel", channel: parsed.channel };
111→      case "friends":
112→        return { type: "friends" };
113→      case "add-friend":
114→        return { type: "add_friend", target: parsed.target };
115→      case "remove-friend":
116→        return { type: "del_friend", target: parsed.target };
117→      case "ignored":
118→        return { type: "ignored" };
119→      case "add-ignore":
120→        return { type: "add_ignore", target: parsed.target };
121→      case "remove-ignore":
122→        return { type: "del_ignore", target: parsed.target };
123→      case "roll":
124→        return parsed;
125→      case "unimplemented":
126→        return parsed;
127→      default:
128→        return { type: "say", message: line };
129→    }
130→  }
131→
132→  const spaceIdx = line.indexOf(" ");
133→  const verb = spaceIdx === -1 ? line : line.slice(0, spaceIdx);
134→  const rest = spaceIdx === -1 ? "" : line.slice(spaceIdx + 1);
135→
136→  switch (verb) {
137→    case "SAY":
138→    case "YELL":
139→    case "GUILD":
140→    case "PARTY":
141→    case "EMOTE":
142→    case "DND":
143→    case "AFK":
144→      return {
145→        type: verb.toLowerCase() as
146→          | "say"
147→          | "yell"
148→          | "guild"
149→          | "party"
150→          | "emote"
151→          | "dnd"
152→          | "afk",
153→        message: rest,
154→      };
155→    case "WHISPER": {
156→      const targetEnd = rest.indexOf(" ");
157→      if (targetEnd === -1)
158→        return { type: "whisper", target: rest, message: "" };
159→      return {
160→        type: "whisper",
161→        target: rest.slice(0, targetEnd),
162→        message: rest.slice(targetEnd + 1),
163→      };
164→    }
165→    case "READ":
166→      return { type: "read" };
167→    case "READ_JSON":
168→      return { type: "read_json" };
169→    case "READ_WAIT": {
170→      const ms = parseInt(rest, 10);
171→      if (!Number.isFinite(ms) || ms < 0) return undefined;
172→      return { type: "read_wait", ms: Math.min(ms, 60_000) };
173→    }
174→    case "READ_WAIT_JSON": {
175→      const ms = parseInt(rest, 10);
176→      if (!Number.isFinite(ms) || ms < 0) return undefined;
177→      return { type: "read_wait_json", ms: Math.min(ms, 60_000) };
178→    }
179→    case "STOP":
180→      return { type: "stop" };
181→    case "STATUS":
182→      return { type: "status" };
183→    case "WHO":
184→      return rest ? { type: "who", filter: rest } : { type: "who" };
185→    case "WHO_JSON":
186→      return rest ? { type: "who_json", filter: rest } : { type: "who_json" };
187→    case "INVITE":
188→      return rest ? { type: "invite", target: rest } : undefined;
189→    case "KICK":
190→      return rest ? { type: "kick", target: rest } : undefined;
191→    case "LEAVE":
192→      if (rest) {
193→        const channel = rest.split(" ")[0]!;
194→        return { type: "leave_channel", channel };
195→      }
196→      return { type: "leave" };
197→    case "LEADER":
198→      return rest ? { type: "leader", target: rest } : undefined;
199→    case "ACCEPT":
200→      return { type: "accept" };
201→    case "DECLINE":
202→      return { type: "decline" };
203→    case "NEARBY":
204→      return { type: "nearby" };
205→    case "NEARBY_JSON":
206→      return { type: "nearby_json" };
207→    case "FRIENDS":
208→      return { type: "friends" };
209→    case "FRIENDS_JSON":
210→      return { type: "friends_json" };
211→    case "ADD_FRIEND":
212→      return rest ? { type: "add_friend", target: rest } : undefined;
213→    case "DEL_FRIEND":
214→      return rest ? { type: "del_friend", target: rest } : undefined;
215→    case "IGNORED":
216→      return { type: "ignored" };
217→    case "IGNORED_JSON":
218→      return { type: "ignored_json" };
219→    case "ADD_IGNORE":
220→      return rest ? { type: "add_ignore", target: rest } : undefined;
221→    case "DEL_IGNORE":
222→      return rest ? { type: "del_ignore", target: rest } : undefined;
223→    case "JOIN": {
224→      if (!rest) return undefined;
225→      const [channel, password] = rest.split(" ") as [string, string?];
226→      return { type: "join_channel", channel, password };
227→    }
228→    case "GINVITE":
229→    case "GKICK":
230→    case "GLEAVE":
231→    case "GPROMOTE":
232→      return { type: "unimplemented", feature: "Guild management" };
233→    case "MAIL":
234→      return { type: "unimplemented", feature: "Mail" };
235→    case "ROLL": {
236→      const parts = rest.split(" ").filter(Boolean);
237→      if (parts.length >= 2)
238→        return {
239→          type: "roll",
240→          min: parseInt(parts[0]!, 10),
241→          max: parseInt(parts[1]!, 10),
242→        };
243→      if (parts.length === 1)
244→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
245→      return { type: "roll", min: 1, max: 100 };
246→    }
247→    default:
248→      return line ? { type: "chat", message: line } : undefined;
249→  }
250→}
