252→export function writeLines(socket: IpcSocket, lines: string[]): void {
253→  for (const line of lines) socket.write(line + "\n");
254→  socket.write("\n");
255→}
256→
257→function drainText(events: RingBuffer<EventEntry>): string[] {
258→  return events.drain().flatMap((e) => (e.text !== undefined ? [e.text] : []));
259→}
260→
261→function drainJson(events: RingBuffer<EventEntry>): string[] {
262→  return events.drain().map((e) => e.json);
263→}
264→
265→function sliceText(events: RingBuffer<EventEntry>, from: number): string[] {
266→  return events
267→    .slice(from)
268→    .flatMap((e) => (e.text !== undefined ? [e.text] : []));
269→}
270→
271→function sliceJson(events: RingBuffer<EventEntry>, from: number): string[] {
272→  return events.slice(from).map((e) => e.json);
273→}
