275→export async function dispatchCommand(
276→  cmd: IpcCommand,
277→  handle: WorldHandle,
278→  events: RingBuffer<EventEntry>,
279→  socket: IpcSocket,
280→  cleanup: () => void,
281→): Promise<boolean> {
282→  switch (cmd.type) {
283→    case "chat": {
284→      handle.sendInCurrentMode(cmd.message);
285→      const mode = handle.getLastChatMode();
286→      const label =
287→        mode.type === "whisper"
288→          ? `WHISPER ${mode.target}`
289→          : mode.type === "channel"
290→            ? `CHANNEL ${mode.channel}`
291→            : mode.type.toUpperCase();
292→      writeLines(socket, [`OK ${label}`]);
293→      return false;
294→    }
295→    case "say":
296→      handle.sendSay(cmd.message);
297→      writeLines(socket, ["OK"]);
298→      return false;
299→    case "yell":
300→      handle.sendYell(cmd.message);
301→      writeLines(socket, ["OK"]);
302→      return false;
303→    case "guild":
304→      handle.sendGuild(cmd.message);
305→      writeLines(socket, ["OK"]);
306→      return false;
307→    case "party":
308→      handle.sendParty(cmd.message);
309→      writeLines(socket, ["OK"]);
310→      return false;
311→    case "emote":
312→      handle.sendEmote(cmd.message);
313→      writeLines(socket, ["OK"]);
314→      return false;
315→    case "dnd":
316→      handle.sendDnd(cmd.message);
317→      writeLines(socket, ["OK"]);
318→      return false;
319→    case "afk":
320→      handle.sendAfk(cmd.message);
321→      writeLines(socket, ["OK"]);
322→      return false;
323→    case "whisper":
324→      handle.sendWhisper(cmd.target, cmd.message);
325→      writeLines(socket, ["OK"]);
326→      return false;
327→    case "roll":
328→      handle.sendRoll(cmd.min, cmd.max);
329→      writeLines(socket, ["OK"]);
330→      return false;
331→    case "read":
332→      writeLines(socket, drainText(events));
333→      return false;
334→    case "read_json":
335→      writeLines(socket, drainJson(events));
336→      return false;
337→    case "read_wait": {
338→      const start = events.writePos;
339→      await new Promise<void>((resolve) => {
340→        setTimeout(() => {
341→          writeLines(socket, sliceText(events, start));
342→          resolve();
343→        }, cmd.ms);
344→      });
345→      return false;
346→    }
347→    case "read_wait_json": {
348→      const start = events.writePos;
349→      await new Promise<void>((resolve) => {
350→        setTimeout(() => {
351→          writeLines(socket, sliceJson(events, start));
352→          resolve();
353→        }, cmd.ms);
354→      });
355→      return false;
356→    }
357→    case "stop":
358→      writeLines(socket, ["OK"]);
359→      cleanup();
360→      return true;
361→    case "status":
362→      writeLines(socket, ["CONNECTED"]);
363→      return false;
364→    case "who": {
365→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
366→      writeLines(socket, formatWhoResults(results).split("\n"));
367→      return false;
368→    }
369→    case "who_json": {
370→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
371→      writeLines(socket, [formatWhoResultsJson(results)]);
372→      return false;
373→    }
374→    case "invite":
375→      handle.invite(cmd.target);
376→      writeLines(socket, ["OK"]);
377→      return false;
378→    case "kick":
379→      handle.uninvite(cmd.target);
380→      writeLines(socket, ["OK"]);
381→      return false;
382→    case "leave":
383→      handle.leaveGroup();
384→      writeLines(socket, ["OK"]);
385→      return false;
386→    case "leader":
387→      handle.setLeader(cmd.target);
388→      writeLines(socket, ["OK"]);
389→      return false;
390→    case "accept":
391→      handle.acceptInvite();
392→      writeLines(socket, ["OK"]);
393→      return false;
394→    case "decline":
395→      handle.declineInvite();
396→      writeLines(socket, ["OK"]);
397→      return false;
398→    case "nearby": {
399→      const entities = handle.getNearbyEntities();
400→      writeLines(socket, entities.map(formatNearbyLine));
401→      return false;
402→    }
403→    case "nearby_json": {
404→      const entities = handle.getNearbyEntities();
405→      writeLines(
406→        socket,
407→        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
408→      );
409→      return false;
410→    }
411→    case "friends": {
412→      const friends = handle.getFriends();
413→      writeLines(socket, formatFriendList(friends).split("\n"));
414→      return false;
415→    }
416→    case "friends_json": {
417→      const friends = handle.getFriends();
418→      writeLines(socket, [formatFriendListJson(friends)]);
419→      return false;
420→    }
421→    case "add_friend":
422→      handle.addFriend(cmd.target);
423→      writeLines(socket, ["OK"]);
424→      return false;
425→    case "del_friend":
426→      handle.removeFriend(cmd.target);
427→      writeLines(socket, ["OK"]);
428→      return false;
429→    case "ignored": {
430→      const ignored = handle.getIgnored();
431→      writeLines(socket, formatIgnoreList(ignored).split("\n"));
432→      return false;
433→    }
434→    case "ignored_json": {
435→      const ignored = handle.getIgnored();
436→      writeLines(socket, [formatIgnoreListJson(ignored)]);
437→      return false;
438→    }
439→    case "add_ignore":
440→      handle.addIgnore(cmd.target);
441→      writeLines(socket, ["OK"]);
442→      return false;
443→    case "del_ignore":
444→      handle.removeIgnore(cmd.target);
445→      writeLines(socket, ["OK"]);
446→      return false;
447→    case "join_channel":
448→      handle.joinChannel(cmd.channel, cmd.password);
449→      writeLines(socket, ["OK"]);
450→      return false;
451→    case "leave_channel":
452→      handle.leaveChannel(cmd.channel);
453→      writeLines(socket, ["OK"]);
454→      return false;
455→    case "unimplemented":
456→      writeLines(socket, [`UNIMPLEMENTED ${cmd.feature}`]);
457→      return false;
458→  }
459→}
