461→function objectTypeName(type: ObjectType): string {
462→  switch (type) {
463→    case ObjectType.UNIT:
464→      return "NPC";
465→    case ObjectType.PLAYER:
466→      return "Player";
467→    default:
468→      return `type ${type}`;
469→  }
470→}
471→
472→function formatNearbyLine(entity: Entity): string {
473→  if (
474→    entity.objectType === ObjectType.UNIT ||
475→    entity.objectType === ObjectType.PLAYER
476→  ) {
477→    const unit = entity as UnitEntity;
478→    const name = entity.name ?? "Unknown";
479→    const kind = objectTypeName(entity.objectType);
480→    const level = unit.level > 0 ? `, level ${unit.level}` : "";
481→    const hp = `HP ${unit.health}/${unit.maxHealth}`;
482→    const pos = entity.position
483→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
484→      : "";
485→    return `${name} (${kind}${level}) ${hp}${pos}`;
486→  }
487→  if (entity.objectType === ObjectType.GAMEOBJECT) {
488→    const name = entity.name ?? "Unknown";
489→    const pos = entity.position
490→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
491→      : "";
492→    return `${name} (GameObject)${pos}`;
493→  }
494→  return `Entity 0x${entity.guid.toString(16)} (${objectTypeName(entity.objectType)})`;
495→}
496→
497→function objectTypeString(type: ObjectType): string {
498→  switch (type) {
499→    case ObjectType.UNIT:
500→      return "unit";
501→    case ObjectType.PLAYER:
502→      return "player";
503→    case ObjectType.GAMEOBJECT:
504→      return "gameobject";
505→    default:
506→      return "object";
507→  }
508→}
509→
510→function formatNearbyObj(entity: Entity): Record<string, unknown> {
511→  const obj: Record<string, unknown> = {
512→    guid: `0x${entity.guid.toString(16)}`,
513→    type: objectTypeString(entity.objectType),
514→    name: entity.name,
515→  };
516→  if (
517→    entity.objectType === ObjectType.UNIT ||
518→    entity.objectType === ObjectType.PLAYER
519→  ) {
520→    const unit = entity as UnitEntity;
521→    obj["level"] = unit.level;
522→    obj["health"] = unit.health;
523→    obj["maxHealth"] = unit.maxHealth;
524→  }
525→  if (entity.objectType === ObjectType.GAMEOBJECT) {
526→    obj["gameObjectType"] = (entity as GameObjectEntity).gameObjectType;
527→  }
528→  if (entity.position) {
529→    obj["x"] = entity.position.x;
530→    obj["y"] = entity.position.y;
531→    obj["z"] = entity.position.z;
532→  }
533→  return obj;
534→}
535→
536→function formatGroupEventObj(event: GroupEvent): Record<string, unknown> {
537→  switch (event.type) {
538→    case "invite_received":
539→      return { type: "GROUP_INVITE", from: event.from };
540→    case "command_result":
541→      return {
542→        type: "GROUP_COMMAND_RESULT",
543→        operation: event.operation,
544→        target: event.target,
545→        result: event.result,
546→      };
547→    case "leader_changed":
548→      return { type: "GROUP_LEADER_CHANGED", name: event.name };
549→    case "group_destroyed":
550→      return { type: "GROUP_DESTROYED" };
551→    case "kicked":
552→      return { type: "GROUP_KICKED" };
553→    case "invite_declined":
554→      return { type: "GROUP_INVITE_DECLINED", name: event.name };
555→    case "group_list":
556→      return {
557→        type: "GROUP_LIST",
558→        members: event.members.map((m) => ({
559→          name: m.name,
560→          online: m.online,
561→        })),
562→        leader: event.leader,
563→      };
564→    case "member_stats":
565→      return {
566→        type: "PARTY_MEMBER_STATS",
567→        guidLow: event.guidLow,
568→        online: event.online,
569→        hp: event.hp,
570→        maxHp: event.maxHp,
571→        level: event.level,
572→      };
573→  }
574→}
