export function parseCharacterList(r: PacketReader): CharacterInfo[] {
  const count = r.uint8();
  const chars: CharacterInfo[] = [];
  for (let i = 0; i < count; i++) {
    const guidLow = r.uint32LE();
    const guidHigh = r.uint32LE();
    const name = r.cString();
    const race = r.uint8();
    const classId = r.uint8();
    const gender = r.uint8();
    r.skip(4);
    r.skip(1);
    const level = r.uint8();
    const zone = r.uint32LE();
    const map = r.uint32LE();
    r.skip(4 * 3);
    r.skip(4);
    r.skip(4);
    r.skip(4);
    r.skip(1);
    r.skip(4 * 3);
    for (let j = 0; j < 23; j++) {
      r.skip(4 + 1 + 4);
    }
    chars.push({
      guidLow,
      guidHigh,
      name,
      race,
      classId,
      gender,
      level,
      zone,
      map,
    });
  }
  return chars;
}

